  1→import {
  2→  checkout,
  3→  dodopayments,
  4→  portal,
  5→  webhooks,
  6→} from "@dodopayments/better-auth";
  7→import { and, eq, gt } from "drizzle-orm";
  8→import { drizzleAdapter } from "better-auth/adapters/drizzle";
  9→import { betterAuth } from "better-auth/minimal";
 10→import { z } from "zod";
 11→import { admin, oAuthProxy } from "better-auth/plugins";
 12→import { InvitationAcceptedEmail } from "@/emails/invitation-accepted-email";
 13→import { InvitationRejectedEmail } from "@/emails/invitation-rejected-email";
 14→import { OrgInvitationEmail } from "@/emails/org-invitation-email";
 15→import { PasswordResetEmail } from "@/emails/password-reset-email";
 16→import { VerificationEmail } from "@/emails/verification-email";
 17→import { WelcomeEmail } from "@/emails/welcome-email";
 18→import { env as clientEnv } from "@/env/client";
 19→import { env as serverEnv } from "@/env/server";
 20→import { sendEmail } from "@/lib/email/send";
 21→import { db } from "@/server/db";
 22→import * as schema from "@/server/db/models/auth.model";
 23→import { platformInvitation } from "@/server/db/models/platform-invitation.model";
 24→import { orgRepo } from "@/server/db/repos/org.repo";
 25→import { BILLING_CONFIG } from "./billing-config";
 26→import { dodo } from "./dodo";
 27→import { slugify } from "./org-utils";
 28→import { organization } from "better-auth/plugins";
 29→import { isProduction } from "better-auth";
 30→
 31→// ── Webhook payload schemas ────────────────────────────────────────────────────
 32→
 33→const subscriptionActiveSchema = z.object({
 34→  data: z.object({
 35→    subscription_id: z.string(),
 36→    metadata: z.object({ organizationId: z.string() }),
 37→  }),
 38→});
 39→
 40→const subscriptionEventSchema = z.object({
 41→  data: z.object({
 42→    subscription_id: z.string(),
 43→    metadata: z.object({ organizationId: z.string() }),
 44→  }),
 45→});
 46→
 47→// Extracted so both the user.create.after hook and the session repair path share
 48→// the same org-creation logic without duplication.
 49→// Safe to reference `auth` here because this function is only ever called at
 50→// runtime (inside hooks), never at module-initialisation time.
 51→async function createDefaultOrgForUser(user: { id: string; name: string }) {
 52→  const name = `${user.name}'s Workspace`;
 53→  const suffix = crypto.randomUUID().slice(0, 8);
 54→  const slug = `${slugify(user.name)}-${suffix}`;
 55→  const org = await auth.api.createOrganization({
 56→    body: { name, slug, userId: user.id },
 57→  });
 58→  if (org) {
 59→    const trialExpiresAt = new Date(
 60→      Date.now() + BILLING_CONFIG.trialDays * 24 * 60 * 60 * 1000,
 61→    );
 62→    await orgRepo.setTrialExpiresAt(org.id, trialExpiresAt);
 63→  }
 64→  return org;
 65→}
 66→
 67→export const auth = betterAuth({
 68→  baseURL: clientEnv.NEXT_PUBLIC_SERVER_URL || "http://localhost:3000",
 69→  session: {
 70→    cookieCache: {
 71→      enabled: true,
 72→      maxAge: 5 * 60, // 5 minutes
 73→    },
 74→  },
 75→  database: drizzleAdapter(db, {
 76→    provider: "pg",
 77→    schema,
 78→  }),
 79→  databaseHooks: {
 80→    user: {
 81→      create: {
 82→        before: async (user) => {
 83→          if (serverEnv.ENABLE_SIGNUPS !== "true") {
 84→            const platformInvite = await db.query.platformInvitation.findFirst({
 85→              where: and(
 86→                eq(platformInvitation.email, user.email),
 87→                gt(platformInvitation.expiresAt, new Date()),
 88→              ),
 89→            });
 90→            if (!platformInvite) {
 91→              throw new Error(
 92→                "Signups are currently disabled. Please join the waitlist.",
 93→              );
 94→            }
 95→          }
 96→          return { data: user };
 97→        },
 98→        after: async (user) => {
 99→          try {
100→            await createDefaultOrgForUser(user);
101→          } catch (err) {
102→            // Do not rethrow — user creation must complete cleanly.
103→            // The session hook will repair the missing org on first login.
104→            console.error(
105→              `[auth] user.create.after: failed to create default org for user ${user.id}`,
106→              err,
107→            );
108→          }
109→          // OAuth users (e.g. Google) arrive already verified — send welcome
110→          // email now. Email/password users get it via afterEmailVerification.
111→          if (!user.emailVerified) return;
112→          void sendEmail({
113→            to: user.email,
114→            subject: "Welcome to RunAgents",
115→            react: WelcomeEmail({
116→              userName: user.name,
117→              trialDays: BILLING_CONFIG.trialDays,
118→            }),
119→            text: `Welcome to RunAgents! You have a ${BILLING_CONFIG.trialDays}-day free trial. Get started at https://runagents.co/dashboard`,
120→          });
121→        },
122→      },
123→    },
124→    session: {
125→      create: {
126→        before: async (session) => {
127→
128→          if (!session.activeOrganizationId) {
129→            const membership = await orgRepo.findFirstMemberByUser(session.userId);
130→            if (membership) {
131→              return {
132→                data: {
133→                  ...session,
134→                  activeOrganizationId: membership.organizationId,
135→                },
136→              };
137→            }
138→
139→            // No membership found — the after hook likely failed during sign-up.
140→            // Attempt to repair by creating the org now, before the session is issued.
141→            try {
142→              const userRow = await db.query.user.findFirst({
143→                where: eq(schema.user.id, session.userId),
144→              });
145→              if (userRow) {
146→                await createDefaultOrgForUser(userRow);
147→                const repairedMembership = await orgRepo.findFirstMemberByUser(session.userId);
148→                if (repairedMembership) {
149→                  return {
150→                    data: {
151→                      ...session,
152→                      activeOrganizationId: repairedMembership.organizationId,
153→                    },
154→                  };
155→                }
156→              }
157→            } catch (err) {
158→              console.error(
159→                `[auth] session.create.before: org repair failed for user ${session.userId}`,
160→                err,
161→              );
162→              // Fall through — session issued without activeOrganizationId.
163→            }
164→          }
165→          return { data: session };
166→        },
167→      },
168→    },
169→  },
170→  trustedOrigins: [clientEnv.NEXT_PUBLIC_SERVER_URL],
171→  emailAndPassword: {
172→    enabled: true,
173→    requireEmailVerification: false,
174→    async sendResetPassword({ user, url }) {
175→      const result = await sendEmail({
176→        to: user.email,
177→        subject: "Reset your password",
178→        react: PasswordResetEmail({ url, userName: user.name }),
179→        text: `Reset your password by visiting: ${url}`,
180→      });
181→      if (!result.success) {
182→        throw new Error(`Failed to send password reset email: ${result.error}`);
183→      }
184→    },
185→  },
186→  socialProviders: {
187→    google: {
188→      clientId: serverEnv.GOOGLE_CLIENT_ID,
189→      clientSecret: serverEnv.GOOGLE_CLIENT_SECRET,
190→      enabled: !!(serverEnv.GOOGLE_CLIENT_ID && serverEnv.GOOGLE_CLIENT_SECRET),
191→      redirectURI: `${clientEnv.NEXT_PUBLIC_SERVER_URL}/api/auth/callback/google`,
192→    },
193→  },
194→  emailVerification: {
195→    sendOnSignUp: true,
196→    autoSignInAfterVerification: true,
197→    async afterEmailVerification(user) {
198→      void sendEmail({
199→        to: user.email,
200→        subject: "Welcome to RunAgents",
201→        react: WelcomeEmail({
202→          userName: user.name,
203→          trialDays: BILLING_CONFIG.trialDays,
204→        }),
205→        text: `Welcome to RunAgents! You have a ${BILLING_CONFIG.trialDays}-day free trial. Get started at https://runagents.co/dashboard`,
206→      });
207→    },
208→    async sendVerificationEmail({ user, url }) {
209→      const urlObj = new URL(url);
210→      urlObj.searchParams.set("callbackURL", "/email-verification");
211→      const verificationUrl = urlObj.toString();
212→      const result = await sendEmail({
213→        to: user.email,
214→        subject: "Verify your email address",
215→        react: VerificationEmail({ url: verificationUrl, userName: user.name }),
216→        text: `Verify your email address by visiting: ${verificationUrl}`,
217→      });
218→      if (!result.success) {
219→        throw new Error(`Failed to send verification email: ${result.error}`);
220→      }
221→    },
222→  },
223→  user: {},
224→  plugins: [
225→    ...(isProduction ? [] : [oAuthProxy({ productionURL: clientEnv.NEXT_PUBLIC_SERVER_URL })]),
226→    admin(),
227→    dodopayments({
228→      client: dodo,
229→      createCustomerOnSignUp: true,
230→      use: [
231→        checkout({
232→          products: Object.values(BILLING_CONFIG.plans).map((p) => ({
233→            productId: p.productId,
234→            slug: p.slug,
235→          })),
236→          successUrl: "/billing/return",
237→          authenticatedUsersOnly: true,
238→        }),
239→        portal(),
240→        webhooks({
241→          webhookKey: serverEnv.DODO_PAYMENTS_WEBHOOK_SECRET,
242→          // Set subscriptionId on activation/renewal
243→          onSubscriptionActive: async (payload) => {
244→            const result = subscriptionActiveSchema.safeParse(payload);
245→            if (!result.success) {
246→              console.error("[webhook] onSubscriptionActive: invalid payload", result.error.flatten());
247→              return;
248→            }
249→            const { subscription_id: subId, metadata: { organizationId: orgId } } = result.data.data;
250→            await orgRepo.setSubscriptionId(orgId, subId);
251→          },
252→          // Clear subscriptionId on cancellation
253→          onSubscriptionCancelled: async (payload) => {
254→            const result = subscriptionEventSchema.safeParse(payload);
255→            if (!result.success) {
256→              console.error("[webhook] onSubscriptionCancelled: invalid payload", result.error.flatten());
257→              return;
258→            }
259→            const { subscription_id: subId, metadata: { organizationId: orgId } } = result.data.data;
260→            await orgRepo.clearSubscriptionIdIfMatches(orgId, subId);
261→          },
262→          // Clear subscriptionId on expiry
263→          onSubscriptionExpired: async (payload) => {
264→            const result = subscriptionEventSchema.safeParse(payload);
265→            if (!result.success) {
266→              console.error("[webhook] onSubscriptionExpired: invalid payload", result.error.flatten());
267→              return;
268→            }
269→            const { subscription_id: subId, metadata: { organizationId: orgId } } = result.data.data;
270→            await orgRepo.clearSubscriptionIdIfMatches(orgId, subId);
271→          },
272→        }),
273→      ],
274→    }),
275→    organization({
276→      creatorRole: "owner",
277→      async sendInvitationEmail(data) {
278→        const inviteLink = `${clientEnv.NEXT_PUBLIC_SERVER_URL}/invite/${data.id}`;
279→        await sendEmail({
280→          to: data.email,
281→          subject: `Join ${data.organization.name} on RunAgents`,
282→          react: OrgInvitationEmail({
283→            inviteLink,
284→            inviterName: data.inviter.user.name,
285→            organizationName: data.organization.name,
286→            role: data.role,
287→          }),
288→        });
289→      },
290→      organizationHooks: {
291→        afterAcceptInvitation: async ({ invitation, user, organization }) => {
292→          const inviter = await db.query.user.findFirst({
293→            where: eq(schema.user.id, invitation.inviterId),
294→          });
295→          if (!inviter) return;
296→          void sendEmail({
297→            to: inviter.email,
298→            subject: `${user.name} joined ${organization.name}`,
299→            react: InvitationAcceptedEmail({
300→              memberName: user.name,
301→              memberEmail: user.email,
302→              organizationName: organization.name,
303→              role: invitation.role,
304→            }),
305→          });
306→        },
307→        afterRejectInvitation: async ({ invitation, user, organization }) => {
308→          const inviter = await db.query.user.findFirst({
309→            where: eq(schema.user.id, invitation.inviterId),
310→          });
311→          if (!inviter) return;
312→          void sendEmail({
313→            to: inviter.email,
314→            subject: `Invitation to ${organization.name} was declined`,
315→            react: InvitationRejectedEmail({
316→              memberEmail: user.email,
317→              organizationName: organization.name,
318→            }),
319→          });
320→        },
321→      },
322→      schema: {
323→        organization: {
324→          additionalFields: {
325→            trialExpiresAt: { type: "date", required: false, input: false },
326→            subscriptionId: { type: "string", required: false, input: false },
327→          },
328→        },
329→      },
330→    }),
331→  ],
332→});
